const RE = /^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?$/;
function bad(s){ return !s || typeof s !== "string" || !RE.test(s); }
const i = $input.first().json;
if (bad(i.namespace)) return [{json: {blocked: true, ok: false, detail: "invalid or missing namespace"}}];
let url = `https://kubernetes.default.svc/api/v1/namespaces/${i.namespace}/pods`;
if (i.selector) url += `?labelSelector=${encodeURIComponent(i.selector)}`;
return [{json: {url, namespace: i.namespace}}];

const r = $input.first().json;
if (r.blocked) return [{json: {ok: false, detail: r.detail}}];
if (r.statusCode >= 400) return [{json: {ok: false, detail: `K8s API ${r.statusCode}: ${JSON.stringify(r.body?.message || r.body).slice(0,300)}`}}];
const pods = (r.body.items || []).map(p => ({
  name: p.metadata.name, phase: p.status.phase, node: p.spec.nodeName,
  ready: (p.status.containerStatuses||[]).map(c => `${c.name}:${c.ready?"ready":"not-ready"} restarts=${c.restartCount}` +
    (c.state?.waiting ? ` waiting=${c.state.waiting.reason}` : "") +
    (c.lastState?.terminated ? ` lastExit=${c.lastState.terminated.exitCode}/${c.lastState.terminated.reason}` : "")).join("; ")
}));
return [{json: {ok: true, count: pods.length, pods}}];
